/* ═══════════════════════════════════════════════════════════════════════════
   LiveTradingLock — Paywall modal for live trading access
   Glass morphism overlay shown when unpaid users attempt live trading.
   Primary CTA triggers Stripe checkout for the trader tier.
   ═══════════════════════════════════════════════════════════════════════════ */
import { tokens } from '../styles/tokens';
import useStripeCheckout from '../hooks/useStripeCheckout';

const mono = tokens.font.mono;
const body = tokens.font.sans;

const UNLOCK_FEATURES = [
  { icon: '⚡', label: 'Live broker execution' },
  { icon: '📡', label: 'Real-time signal engine' },
  { icon: '💰', label: 'Capital deployment' },
  { icon: '🛡️', label: 'Risk engine enforcement' },
];

export default function LiveTradingLock({ onDismiss, children }) {
  const { checkout, loading, error } = useStripeCheckout();

  return (
    <div style={{ position: 'relative', minHeight: '80vh' }}>
      {/* Blurred background content */}
      {children && (
        <div style={{
          filter: 'blur(8px)', opacity: 0.25, pointerEvents: 'none',
          userSelect: 'none', position: 'absolute', inset: 0, overflow: 'hidden',
        }}>
          {children}
        </div>
      )}

      {/* Glass overlay */}
      <div style={{
        position: children ? 'absolute' : 'relative',
        inset: 0,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'rgba(11,15,20,0.75)',
        backdropFilter: 'blur(20px)',
        WebkitBackdropFilter: 'blur(20px)',
        zIndex: 10,
        minHeight: children ? 'auto' : '70vh',
      }}>
        <div style={{
          maxWidth: 460,
          width: '100%',
          padding: 40,
          textAlign: 'center',
        }}>
          {/* Lock icon */}
          <div style={{
            width: 72, height: 72, borderRadius: 18,
            margin: '0 auto 24px',
            background: 'rgba(34,197,94,0.08)',
            border: '2px solid rgba(34,197,94,0.2)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}>
            <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke={tokens.color.green} strokeWidth="2">
              <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
              <path d="M7 11V7a5 5 0 0110 0v4" />
            </svg>
          </div>

          {/* Headline */}
          <h2 style={{
            fontFamily: body, fontSize: 24, fontWeight: 800,
            color: tokens.color.text, margin: '0 0 12px',
            letterSpacing: '-0.01em',
          }}>
            Enable Live Execution
          </h2>

          {/* Body */}
          <p style={{
            fontFamily: body, fontSize: 14, color: tokens.color.textSecondary,
            margin: '0 0 28px', lineHeight: 1.6,
          }}>
            Upgrade to deploy real capital through your broker.
            The same signals. The same execution engine. The same risk controls.
            Real money.
          </p>

          {/* What unlocks */}
          <div style={{
            background: 'rgba(34,197,94,0.04)',
            border: '1px solid rgba(34,197,94,0.12)',
            borderRadius: tokens.radius.lg,
            padding: 20,
            marginBottom: 28,
            textAlign: 'left',
          }}>
            <div style={{
              fontFamily: mono, fontSize: 10, fontWeight: 700,
              color: tokens.color.textSecondary, textTransform: 'uppercase',
              letterSpacing: '0.06em', marginBottom: 14,
            }}>
              What Unlocks
            </div>
            {UNLOCK_FEATURES.map((f) => (
              <div key={f.label} style={{
                display: 'flex', alignItems: 'center', gap: 10,
                padding: '7px 0', fontSize: 13, fontFamily: body,
                color: tokens.color.text,
              }}>
                <span style={{ color: tokens.color.green, fontSize: 15 }}>{f.icon}</span>
                {f.label}
              </div>
            ))}
          </div>

          {/* Primary CTA */}
          <button
            onClick={() => checkout('trader')}
            disabled={loading}
            style={{
              width: '100%',
              padding: '14px 32px',
              borderRadius: tokens.radius.md,
              fontSize: 15,
              fontWeight: 800,
              fontFamily: mono,
              color: '#000',
              border: 'none',
              cursor: loading ? 'wait' : 'pointer',
              background: 'linear-gradient(135deg, #22C55E, #16A34A)',
              boxShadow: '0 4px 20px rgba(34,197,94,0.25)',
              letterSpacing: '0.02em',
              opacity: loading ? 0.7 : 1,
              transition: tokens.transition.fast,
              marginBottom: 12,
            }}
          >
            {loading ? 'Redirecting to Checkout...' : 'Start Subscription'}
          </button>

          {error && (
            <div style={{
              fontFamily: body, fontSize: 12, color: tokens.color.red,
              marginBottom: 8,
            }}>
              {error}
            </div>
          )}

          {/* Secondary CTA */}
          <button
            onClick={onDismiss}
            style={{
              background: 'none', border: 'none', cursor: 'pointer',
              fontFamily: body, fontSize: 13, color: tokens.color.textSecondary,
              padding: '8px 16px',
            }}
          >
            Continue Paper Trading
          </button>
        </div>
      </div>
    </div>
  );
}
