// ─── Helpers ────────────────────────────────────────────────────────────────

function fmt$(v) {
  const n = Number(v);
  if (v == null || !isFinite(n)) return '--';
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2 }).format(n);
}

function fmtCompact$(v) {
  const n = Number(v);
  if (v == null || !isFinite(n)) return '--';
  if (Math.abs(n) >= 1e6) return `$${(n / 1e6).toFixed(2)}M`;
  if (Math.abs(n) >= 1e3) return `$${(n / 1e3).toFixed(1)}K`;
  return fmt$(n);
}

function fmtPnl(v) {
  const n = Number(v);
  if (v == null || !isFinite(n)) return { text: '--', color: C.textSecondary };
  const prefix = n >= 0 ? '+' : '';
  return { text: prefix + fmt$(n), color: n >= 0 ? C.green : C.red };
}

function fmtPct(v) {
  const n = Number(v);
  if (v == null || !isFinite(n)) return '--';
  return `${n.toFixed(1)}%`;
}

function fmtSignedPct(v) {
  const n = Number(v);
  if (v == null || !isFinite(n)) return '--';
  const prefix = n >= 0 ? '+' : '';
  return `${prefix}${n.toFixed(2)}%`;
}

function fmtTime(ts) {
  if (!ts) return '--';
  const d = new Date(ts);
  if (isNaN(d.getTime())) return '--';
  return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });
}

function fmtDateTime(ts) {
  if (!ts) return '--';
  const d = new Date(ts);
  if (isNaN(d.getTime())) return '--';
  return d.toLocaleString('en-US', {
    month: 'short', day: 'numeric',
    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false,
  });
}

function fmtRelative(ts) {
  if (!ts) return '--';
  const d = new Date(ts);
  if (isNaN(d.getTime())) return '--';
  const diff = Date.now() - d.getTime();
  if (diff < 60000) return `${Math.floor(diff / 1000)}s ago`;
  if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
  if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
  return `${Math.floor(diff / 86400000)}d ago`;
}

function getMarketStatus() {
  const now = new Date();
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/New_York', hour: 'numeric', minute: 'numeric', weekday: 'short', hour12: false,
  }).formatToParts(now);
  const get = (type) => parts.find(p => p.type === type)?.value || '';
  const dayMap = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
  const day = dayMap[get('weekday')] ?? now.getDay();
  const h = parseInt(get('hour'), 10) || 0;
  const m = parseInt(get('minute'), 10) || 0;
  const t = h * 60 + m;
  if (day === 0 || day === 6) return { label: 'WEEKEND', isOpen: false, color: C.textSecondary };
  if (t >= 570 && t < 960) return { label: 'MARKET OPEN', isOpen: true, color: C.green };
  if (t >= 240 && t < 570) return { label: 'PRE-MARKET', isOpen: false, color: C.blue };
  return { label: 'AFTER HOURS', isOpen: false, color: C.amber };
}

function matchBot(item, selectedBot) {
  if (selectedBot === 'ALL') return true;
  const bot = (item.bot || item.bot_name || '').toUpperCase();
  return bot === selectedBot || bot.includes(selectedBot);
}

function statusColor(status) {
  const st = (status || '').toUpperCase();
  if (st === 'OK' || st === 'LIVE' || st === 'ACTIVE' || st === 'RUNNING') return C.green;
  if (st === 'DEGRADED' || st === 'WARNING' || st === 'SLOW') return C.amber;
  if (st === 'DOWN' || st === 'ERROR' || st === 'OFFLINE' || st === 'DEAD') return C.red;
  return C.textSecondary;
}

function orderStatusColor(status) {
  const st = (status || '').toLowerCase();
  if (st === 'filled') return C.green;
  if (st === 'partial' || st === 'partially_filled') return C.blue;
  if (st === 'pending' || st === 'open' || st === 'new' || st === 'submitted') return C.amber;
  if (st === 'cancelled' || st === 'rejected' || st === 'expired') return C.red;
  return C.textSecondary;
}

// ─── Risk Gauge SVG ─────────────────────────────────────────────────────────

function GaugeMeter({ value, max = 100, color, label, sublabel }) {
  const pct = Math.min(Math.max(Number(value) || 0, 0), max);
  const ratio = pct / max;
  const radius = 50;
  const stroke = 8;
  const circumference = Math.PI * radius;
  const dashOffset = circumference * (1 - ratio);

  let gaugeColor = color || C.green;
  if (ratio > 0.8) gaugeColor = C.red;
  else if (ratio > 0.6) gaugeColor = C.amber;

  return (
    <div className={s.gaugeCard}>
      <div className={s.gaugeLabel}>{label}</div>
      <svg className={s.gaugeSvg} width="120" height="70" viewBox="0 0 120 70">
        <path d="M 10 65 A 50 50 0 0 1 110 65" fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth={stroke} strokeLinecap="round" />
        <path d="M 10 65 A 50 50 0 0 1 110 65" fill="none" stroke={gaugeColor} strokeWidth={stroke} strokeLinecap="round"
          strokeDasharray={circumference} strokeDashoffset={dashOffset}
          style={{ transition: 'stroke-dashoffset 600ms ease, stroke 300ms ease' }}
        />
      </svg>
      <div className={s.gaugeValue} style={{ color: gaugeColor, fontFamily: mono }}>{fmtPct(pct)}</div>
      {sublabel && <div className={s.gaugeSubtext}>{sublabel}</div>}
    </div>
  );
}

