/* ═══════════════════════════════════════════════════════════════════════════
   PostUpgradeFlow — 3-step activation flow shown after successful subscription
   1. Connect Your Broker  2. Configure Risk  3. Deploy Your System
   Each step shows a checkmark when complete. Progress bar at top.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { tokens } from '../styles/tokens';
import { api } from '../utils/api';

const mono = tokens.font.mono;
const body = tokens.font.sans;

const FLOW_KEY = 'aura_post_upgrade_flow';
const FLOW_DISMISSED_KEY = 'aura_post_upgrade_dismissed';

const STEPS = [
  {
    id: 'broker',
    title: 'Connect Your Broker',
    description: 'Link your IBKR account so the system can execute trades on your behalf.',
    route: '/gateway',
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
        <path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71" />
        <path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71" />
      </svg>
    ),
    checkKey: 'brokerConnected',
  },
  {
    id: 'risk',
    title: 'Configure Risk',
    description: 'Set position limits, drawdown thresholds, and daily loss caps.',
    route: '/risk/dynamic',
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
        <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" />
      </svg>
    ),
    checkKey: 'riskConfigured',
  },
  {
    id: 'deploy',
    title: 'Deploy Your System',
    description: 'Activate your bot. Capital starts compounding immediately.',
    route: '/bot-management',
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
        <polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2" />
      </svg>
    ),
    checkKey: 'systemDeployed',
  },
];

function loadFlowState() {
  try { return JSON.parse(localStorage.getItem(FLOW_KEY) || '{}'); } catch { return {}; }
}

function saveFlowState(s) {
  localStorage.setItem(FLOW_KEY, JSON.stringify(s));
}

export default function PostUpgradeFlow() {
  const navigate = useNavigate();
  const [flowState, setFlowState] = useState(loadFlowState);
  const [dismissed, setDismissed] = useState(() => {
    try { return localStorage.getItem(FLOW_DISMISSED_KEY) === '1'; } catch { return false; }
  });

  // Auto-check completion status
  useEffect(() => {
    let cancelled = false;
    async function checkSteps() {
      const state = loadFlowState();
      let changed = false;

      // Check broker connection
      if (!state.brokerConnected) {
        const health = await api('/control/health', { silent: true }).catch(() => null);
        if (health?.gateway_connected) {
          state.brokerConnected = true;
          changed = true;
        }
      }

      // Check risk configuration
      if (!state.riskConfigured) {
        const risk = await api('/risk/exposure', { silent: true }).catch(() => null);
        if (risk && (risk.max_position_size || risk.daily_loss_limit)) {
          state.riskConfigured = true;
          changed = true;
        }
      }

      // Check bot deployment
      if (!state.systemDeployed) {
        const tele = await api('/telemetry/latest', { silent: true }).catch(() => null);
        if (tele?.bots && Object.keys(tele.bots).length > 0) {
          state.systemDeployed = true;
          changed = true;
        }
      }

      if (changed && !cancelled) {
        saveFlowState(state);
        setFlowState({ ...state });
      }
    }

    checkSteps();
    const iv = setInterval(checkSteps, 15000);
    return () => { cancelled = true; clearInterval(iv); };
  }, []);

  const handleDismiss = useCallback(() => {
    setDismissed(true);
    try { localStorage.setItem(FLOW_DISMISSED_KEY, '1'); } catch { /* noop */ }
  }, []);

  if (dismissed) return null;

  const completedCount = STEPS.filter(s => flowState[s.checkKey]).length;
  const allComplete = completedCount === STEPS.length;
  const progressPct = (completedCount / STEPS.length) * 100;

  return (
    <div style={{
      background: 'linear-gradient(135deg, rgba(34,197,94,0.06) 0%, rgba(15,22,32,0.95) 100%)',
      border: '1px solid rgba(34,197,94,0.15)',
      borderRadius: tokens.radius.lg,
      padding: 28,
      marginBottom: 24,
    }}>
      {/* Header */}
      <div style={{
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        marginBottom: 20,
      }}>
        <div>
          <h3 style={{
            fontFamily: body, fontSize: 18, fontWeight: 800,
            color: tokens.color.text, margin: '0 0 4px',
          }}>
            {allComplete ? 'Your System is Live' : 'Activate Your System'}
          </h3>
          <p style={{
            fontFamily: body, fontSize: 13, color: tokens.color.textSecondary,
            margin: 0,
          }}>
            {allComplete
              ? 'Capital is compounding. All systems operational.'
              : `${completedCount} of ${STEPS.length} steps complete`
            }
          </p>
        </div>

        <button
          onClick={handleDismiss}
          style={{
            background: 'none', border: 'none', cursor: 'pointer',
            color: tokens.color.textSecondary, fontSize: 14, padding: 4,
            opacity: 0.6,
          }}
          aria-label="Dismiss activation flow"
        >
          &#10005;
        </button>
      </div>

      {/* Progress bar */}
      <div style={{
        width: '100%', height: 4, borderRadius: 2,
        background: 'rgba(255,255,255,0.06)',
        marginBottom: 24, overflow: 'hidden',
      }}>
        <div style={{
          width: `${progressPct}%`, height: '100%', borderRadius: 2,
          background: allComplete
            ? tokens.color.green
            : 'linear-gradient(90deg, #22C55E, #16A34A)',
          transition: 'width 500ms ease',
        }} />
      </div>

      {/* Steps */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
        {STEPS.map((step, idx) => {
          const isComplete = !!flowState[step.checkKey];
          const isNext = !isComplete && STEPS.slice(0, idx).every(s => flowState[s.checkKey]);

          return (
            <div
              key={step.id}
              onClick={() => !isComplete && navigate(step.route)}
              style={{
                display: 'flex', alignItems: 'center', gap: 16,
                padding: '14px 18px',
                borderRadius: tokens.radius.md,
                background: isComplete
                  ? 'rgba(34,197,94,0.06)'
                  : isNext
                    ? 'rgba(34,197,94,0.03)'
                    : 'rgba(255,255,255,0.02)',
                border: `1px solid ${
                  isComplete ? 'rgba(34,197,94,0.2)' : isNext ? 'rgba(34,197,94,0.1)' : 'rgba(255,255,255,0.04)'
                }`,
                cursor: isComplete ? 'default' : 'pointer',
                opacity: isComplete ? 0.8 : 1,
                transition: tokens.transition.fast,
              }}
            >
              {/* Step indicator */}
              <div style={{
                width: 40, height: 40, borderRadius: 10,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                flexShrink: 0,
                background: isComplete
                  ? 'rgba(34,197,94,0.15)'
                  : 'rgba(255,255,255,0.04)',
                color: isComplete ? tokens.color.green : tokens.color.textSecondary,
              }}>
                {isComplete ? (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={tokens.color.green} strokeWidth="3">
                    <polyline points="20 6 9 17 4 12" />
                  </svg>
                ) : (
                  step.icon
                )}
              </div>

              {/* Text */}
              <div style={{ flex: 1 }}>
                <div style={{
                  fontFamily: body, fontSize: 14, fontWeight: 700,
                  color: isComplete ? tokens.color.textSecondary : tokens.color.text,
                  textDecoration: isComplete ? 'line-through' : 'none',
                  marginBottom: 2,
                }}>
                  {step.title}
                </div>
                <div style={{
                  fontFamily: body, fontSize: 12, color: tokens.color.textSecondary,
                  lineHeight: 1.4,
                }}>
                  {step.description}
                </div>
              </div>

              {/* Arrow for incomplete steps */}
              {!isComplete && (
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none"
                  stroke={tokens.color.textSecondary} strokeWidth="2" style={{ flexShrink: 0 }}>
                  <polyline points="9 18 15 12 9 6" />
                </svg>
              )}
            </div>
          );
        })}
      </div>

      {/* Final message when all complete */}
      {allComplete && (
        <div style={{
          textAlign: 'center', marginTop: 20, padding: '16px 0',
          borderTop: '1px solid rgba(34,197,94,0.1)',
        }}>
          <div style={{
            fontFamily: body, fontSize: 15, fontWeight: 700,
            color: tokens.color.green, marginBottom: 4,
          }}>
            Your system is live. Capital is compounding.
          </div>
          <div style={{
            fontFamily: body, fontSize: 12, color: tokens.color.textSecondary,
          }}>
            Monitor performance on the Live Trading page.
          </div>
        </div>
      )}
    </div>
  );
}
